     1→/**
     2→ * SimpleSpatialIndex - O(n) Placeholder Implementation
     3→ *
     4→ * This is a simple linear scan implementation of ISpatialIndex.
     5→ * It serves as a placeholder until STATE-ARCH-001.Phase2 implements
     6→ * the full RBush-based spatial index with TypedArray backing.
     7→ *
     8→ * Performance characteristics:
     9→ * - load(): O(n)
    10→ * - insert(): O(1)
    11→ * - remove(): O(n)
    12→ * - queryViewport(): O(n) - iterates all items
    13→ * - queryRadius(): O(n)
    14→ * - queryNearest(): O(n)
    15→ *
    16→ * For 60k tasks, this is acceptable for now but will be replaced
    17→ * with O(log n) R-tree queries in the future.
    18→ *
    19→ * @see STATE-ARCH-001.Phase2 for the optimized implementation
    20→ */
    21→
    22→import type {
    23→  ISpatialIndex,
    24→  SpatialItem,
    25→  SpatialIndexStats,
    26→  SpatialQueryResult,
    27→  ViewportBounds,
    28→} from './types';
    29→import { rectanglesIntersect, distanceToCenter } from './types';
    30→
    31→export class SimpleSpatialIndex implements ISpatialIndex {
    32→  private items: Map<string, SpatialItem> = new Map();
    33→  private stats: SpatialIndexStats = {
    34→    itemCount: 0,
    35→  };
    36→
    37→  /**
    38→   * Bulk load items into the index.
    39→   * For SimpleSpatialIndex, this just stores items in a Map.
    40→   */
    41→  load(items: SpatialItem[]): void {
    42→    const startTime = performance.now();
    43→
    44→    this.items.clear();
    45→    for (const item of items) {
    46→      this.items.set(item.id, item);
    47→    }
    48→
    49→    this.stats.itemCount = this.items.size;
    50→    this.stats.lastBuildTimeMs = performance.now() - startTime;
    51→  }
    52→
    53→  /**
    54→   * Insert a single item.
    55→   */
