     1→/**
     2→ * useCulledInstances - Hook for viewport-based instance culling
     3→ *
     4→ * This hook optimizes InstancedMesh rendering by:
     5→ * 1. Querying a spatial index for visible items
     6→ * 2. Reordering instances so visible ones are at the front
     7→ * 3. Returning the visible count to set on mesh.count
     8→ *
     9→ * The key insight is that Three.js InstancedMesh renders instances
    10→ * 0 to mesh.count-1. By placing visible instances at the front
    11→ * and setting count to the visible count, we skip hidden instances.
    12→ *
    13→ * Performance characteristics:
    14→ * - Query: O(log n) with R-tree, O(n) with SimpleSpatialIndex
    15→ * - Reorder: O(visible) - only moves pointers, not data
    16→ * - Memory: O(n) for the lookup map
    17→ *
    18→ * Usage in MesoLayer:
    19→ * ```tsx
    20→ * const { visibleTasks, visibleCount } = useCulledInstances(tasks, viewportBounds, spatialIndex);
    21→ * // Use visibleTasks for matrix/color setup
    22→ * // Set mesh.count = visibleCount
    23→ * ```
    24→ *
    25→ * @see PERF-002 Phase 2
    26→ */
    27→
    28→import { useMemo, useRef } from 'react';
    29→import type { TaskRender } from '../data/types';
    30→import type { ViewportBounds, ISpatialIndex } from '../spatial';
    31→
    32→/**
    33→ * Result of culling operation
    34→ */
    35→export interface CulledInstancesResult {
    36→  /**
    37→   * Tasks reordered with visible tasks at the front.
    38→   * The first `visibleCount` items are visible.
    39→   */
    40→  orderedTasks: TaskRender[];
    41→
    42→  /**
    43→   * Number of visible tasks (set this as mesh.count)
    44→   */
    45→  visibleCount: number;
    46→
    47→  /**
    48→   * Map from task ID to its index in orderedTasks.
