/**
 * Interaction State Slice
 *
 * Manages hover, selection, and focus state for task interactions.
 * Uses @mms/toolkit external store pattern for synchronous access.
 *
 * @see F018 - Hover highlight on tasks
 * @see F019 - Click to select task
 * @see F021 - Keyboard navigation for tasks
 */

import { createSyncSlice } from '@mms/toolkit';

// ─────────────────────────────────────────────────────────────
// STATE TYPES
// ─────────────────────────────────────────────────────────────

export interface InteractionSliceState {
  /** Currently hovered task ID (null if none) */
  hoveredTaskId: string | null;

  /** Mouse position in world coordinates (for hover detection) */
  mouseWorldPos: { x: number; y: number } | null;

  /** Currently selected task ID (null if none) - for F019 */
  selectedTaskId: string | null;

  /** Currently keyboard-focused task ID (null if none) - for F021 */
  focusedTaskId: string | null;

  /** Whether cursor is over a hoverable area */
  isHoverable: boolean;
}

// ─────────────────────────────────────────────────────────────
// INITIAL STATE
// ─────────────────────────────────────────────────────────────

const initialState: InteractionSliceState = {
  hoveredTaskId: null,
  mouseWorldPos: null,
  selectedTaskId: null,
  focusedTaskId: null,
  isHoverable: false,
};

// ─────────────────────────────────────────────────────────────
// INTERACTION SLICE
// ─────────────────────────────────────────────────────────────

export const interactionSlice = createSyncSlice({
  id: 'interaction',
  initial: initialState,
  cache: { policy: 'session' },
  reducers: {
    // Hover state
    setHoveredTask(state: InteractionSliceState, payload: string | null) {
      state.hoveredTaskId = payload;
      state.isHoverable = payload !== null;
    },

    setMouseWorldPos(
      state: InteractionSliceState,
      payload: { x: number; y: number } | null
    ) {
      state.mouseWorldPos = payload;
    },

    clearHover(state: InteractionSliceState) {
      state.hoveredTaskId = null;
      state.mouseWorldPos = null;
      state.isHoverable = false;
    },

    // Selection state (F019)
    setSelectedTask(state: InteractionSliceState, payload: string | null) {
      state.selectedTaskId = payload;
    },

    clearSelection(state: InteractionSliceState) {
      state.selectedTaskId = null;
    },

    // Focus state (F021 - keyboard navigation)
    setFocusedTask(state: InteractionSliceState, payload: string | null) {
      state.focusedTaskId = payload;
    },

    clearFocus(state: InteractionSliceState) {
      state.focusedTaskId = null;
    },

    // Reset all
    reset() {
      return initialState;
    },
  },
});

export type InteractionSlice = typeof interactionSlice;

